INSERT INTO public.email_teachings (theme, title, body_text, source_note) VALUES
('ayurveda', 'The Five Great Elements', 'Panchamahabhuta — Ether, Air, Fire, Water, Earth — are held as the building blocks not just of the physical world but of your own body and mind. Every imbalance the Siddhas treated was, at root, an elemental one. Today, notice which element feels dominant in your mood: light and airy, hot and sharp, or heavy and slow.', 'Panchamahabhuta — Agastyar Academy Module 2'),
('ayurveda', 'Your Cosmic Blueprint', 'Prakriti, your birth constitution, is fixed the moment you''re born — a unique ratio of Vata, Pitta, and Kapha that never changes, even as your current state (Vikriti) shifts daily. Knowing your Prakriti is less about a label and more about knowing what balance actually looks like for you specifically, not for anyone else.', 'The Three Doshas — Agastyar Academy Module 3'),
('ayurveda', 'Your Body''s Sacred Fabric', 'The Seven Dhatus — from Rasa (plasma) to Shukra/Artava (reproductive essence) — are the sequential tissues the Siddhas taught the body builds, one nourishing the next. Ojas is considered the eighth, subtlest layer, the refined essence that emerges only when the other seven are truly well-fed.', 'Sapta Dhatu — Agastyar Academy Module 5'),
('ayurveda', 'Living With Earth''s Breath', 'Ritucharya, the seasonal routine, holds that your diet and lifestyle should shift with the six seasons the way a river bends around stone — not by force, but by intelligent accommodation. What worked for your body last season may already be asking to change.', 'Ritucharya — Agastyar Academy Module 9'),
('ayurveda', 'The Six Tastes', 'Every meal, in this tradition, should ideally touch all six tastes — sweet, sour, salty, bitter, pungent, astringent — each nourishing a different dimension of digestion and mood. Notice tomorrow which taste is missing from your plate; it''s often the one your body is quietly asking for.', 'Shad Rasa — The Ayurvedic Kitchen, Agastyar Academy'),
('ayurveda', 'Plant Intelligence', 'Padardha Guna, the classification of herbs by taste, potency, and effect, is how the Siddhas mapped plant medicine long before modern pharmacology existed. Twenty-five foundational herbs form the base of this system — each one, properly understood, a precise tool rather than a generic remedy.', 'Siddha Herbs — Agastyar Academy Module 11'),
('ayurveda', 'The Pulse as Cosmic Language', 'Nadi Vigyan, pulse reading, uses nine distinct pulse positions in the Siddha system to detect imbalance before it becomes disease — a diagnostic art with no real Western parallel. The pulse, in this tradition, is understood to speak before symptoms do.', 'Nadi Vigyan — Agastyar Academy Module 13'),
('ayurveda', 'Detecting What Hasn''t Arrived Yet', 'Kriya Kala describes disease as a six-stage process, most of which happens silently, long before any symptom appears. This is arguably the most powerful preventive framework the Siddhas left behind — the idea that health is protected earliest, not treated latest.', 'Kriya Kala — Agastyar Academy Module 15'),
('ayurveda', 'The Five Great Purifications', 'Panchakarma — Vamana, Virechana, Basti, Nasya, Raktamokshana — is the Ayurvedic science of deep cellular renewal, five distinct purification methods for five different kinds of imbalance. It is not a single cleanse but a precise, individualized protocol.', 'Panchakarma — Agastyar Academy Module 16'),
('ayurveda', '108 Points of Life Force', 'Marma Science, drawn from Sushruta''s ancient surgical texts, maps 108 vital points where life force is said to concentrate in the body — points still used today in bodywork and energy healing. Even a gentle, informed touch on the right Marma point can shift far more than the local area it sits in.', 'Marma Science — Agastyar Academy Module 17'),
('ayurveda', 'The Rarest Siddha Teaching', 'Varma Therapy — the science of energy points, Thokkanam touch, and the nine sacred contacts — was traditionally taught only within Tamil Nadu gurukulas, passed teacher to student, rarely written down. What you have access to here is a genuinely rare transmission.', 'Varma Therapy — Agastyar Academy Module 18'),
('ayurveda', 'The Crown Secret', 'Muppu, sometimes called the universal solvent of the Siddhars, sits at the heart of Siddha alchemy — the pursuit the tradition calls Kaya Kalpa, the science of bodily longevity and renewal. It is considered the most closely guarded teaching in the entire lineage.', 'Siddha Alchemy & Muppu — Agastyar Academy Module 19'),
('ayurveda', 'The Diagnostic Trinity', 'Long before lab tests, the Siddhas diagnosed through Neermani Nool (urine analysis), tongue mapping, and eye reading — three windows into internal imbalance that require no equipment, only trained attention. It''s worth learning to read even one of these in yourself.', 'Siddha Diagnostic Arts — Agastyar Academy Module 14'),
('jyotish', 'The Divine Actors', 'The 9 Grahas — not literal planets but archetypal forces — are described as the divine actors playing out your life''s story across the chart. Learning even one Graha deeply, rather than skimming all nine, tends to open the whole system faster than people expect.', 'Cosmic Architecture: The 9 Grahas — Jyotish Nexus'),
('jyotish', 'Fields of Karmic Expression', 'The 12 Rashis, the zodiac signs, are held in Jyotish as fields where karmic energy expresses itself differently depending on which sign a planet occupies. The same Graha behaves quite differently in a fire sign than a water sign — context changes everything in this system.', '12 Rashis — Jyotish Nexus'),
('jyotish', 'The Map of Your Life''s Karma', 'The 12 Bhavas, the houses, are considered the actual map of a life — career, relationships, health, spirituality, each assigned its own house. A strong planet in a weak house, or a weak planet in a strong house, tells a very different story than the planet alone.', '12 Bhāvas — Jyotish Nexus'),
('jyotish', 'The Master Clock', 'Vimshottari Dasha is a 120-year planetary timing system the Siddhas used to know not just what a chart means, but when it activates. Two people can have similar charts and live very different decades, because their planetary periods unfold in different order.', 'Vimshottari Dasha — Jyotish Nexus'),
('jyotish', 'Today''s Cosmic Weather', 'Gochar, transit science, tracks the planets'' current movement against your fixed birth chart — your personal karmic weather report, updated daily. It''s why the same practice can feel effortless one month and effortful the next; the sky itself has shifted.', 'Transit Science (Gochar) — Jyotish Nexus'),
('jyotish', 'The Soul Chart', 'Navamsha, the ninth divisional chart, is considered by many Jyotish practitioners to reveal more about a person''s inner life and marriage potential than the birth chart alone. It is sometimes called the chart behind the chart.', 'Navamsha (D9) — Jyotish Nexus'),
('jyotish', 'Sixteen Lenses on One Life', 'The Varga system uses sixteen different divisional charts, each one a distinct lens onto a specific life area — career, spirituality, children, longevity. No single chart tells the whole story; the full picture only emerges across all sixteen together.', 'All 16 Divisional Charts — Jyotish Nexus'),
('jyotish', 'Answering Without a Birth Chart', 'Prashna, horary astrology, is the Siddha art of answering a specific question using the exact moment it was asked, with no birth details required at all. It''s a reminder that in this tradition, the present moment itself is considered a complete chart.', 'Prashna Jyotish (Horary) — Jyotish Nexus'),
('jyotish', 'Choosing the Right Moment', 'Muhurta, electional astrology, is the science of selecting the most auspicious moment to begin something — a marriage, a business, a journey. The Siddhas believed timing wasn''t superstition but a real, measurable variable in how easily something unfolds.', 'Muhurta: Electional Mastery — Jyotish Nexus'),
('jyotish', 'The Body in the Chart', 'Medical Jyotish reads disease, healing, and constitution directly through planetary placements, treating the chart as a second body alongside the physical one. Many Siddha remedies were prescribed based on this reading, not on symptoms alone.', 'Medical Jyotish — Jyotish Nexus'),
('jyotish', 'The Secret Palm-Leaf Science', 'Bhrigu Nandi Nadi is a 5,000-year-old predictive system, said to have been recorded on palm leaves by the sage Bhrigu for souls not yet born — an extraordinary, and extraordinarily rare, branch of Jyotish. Very few practitioners in the world still hold this knowledge intact.', 'Bhrigu Nandi Nadi System — Jyotish Nexus'),
('jyotish', 'Time as a Spiral, Not a Line', 'Kalachakra Dasha is considered one of the most advanced timing systems in Jyotish, treating time not as a straight line but as a spiral returning to itself at different depths. It''s a genuinely different way of understanding when things happen in a life.', 'Kālachakra Dasha — Jyotish Nexus'),
('jyotish', 'The Breath as Oracle', 'Svara Shastra, breath astrology, holds that which nostril is dominant at any given moment carries its own predictive meaning — considered by some the most secret oracle in the entire Siddha tradition. The answer, in this practice, is quite literally always with you.', 'Svara Śāstra: Breath Astrology — Jyotish Nexus'),
('jyotish', 'Sound as Planetary Remedy', 'Jyotish & Mantra Vidya pairs each Graha with its own seed mantra — a sonic remedy for planetary imbalance that predates modern gemstone or color therapy by millennia. Sound, in this system, is considered the most direct way to pacify a difficult planetary period.', 'Jyotish & Mantra Vidya — Jyotish Nexus'),
('pranayama', 'The Five Pranas', 'The Siddhas taught that Prana, life force, moves through the body in five distinct currents — Prana, Apana, Samana, Udana, Vyana — each governing a different function, from breath to elimination to speech. Most breathwork practice is, at its root, an attempt to bring these five into right relationship.', 'Five Pranas — Pranayama Fundamentals, Agastyar Academy'),
('pranayama', 'Bhastrika, the Bellows Breath', 'Bhastrika — forceful, rhythmic breathing through the nose — was used by the Siddhas to build internal heat and clear stagnation quickly, the opposite approach to the calming breaths. It is a practice of a few rounds, not many; more is not always more in Pranayama.', 'Bhastrika — Pranayama Fundamentals, Agastyar Academy'),
('mantra_practice', 'A Practice, Not a Performance', 'A mantra practiced imperfectly every day outperforms a mantra recited perfectly once a month — consistency, in this tradition, is considered more powerful than precision. Don''t wait until you feel ready; the readiness tends to arrive through the doing, not before it.', 'Nada Mantra Academy, foundational teaching'),
('mantra_practice', 'The Count Behind the Chant', 'Mala counting — 108 repetitions — isn''t arbitrary; 108 appears throughout Vedic cosmology as a number of completion. Using your fingers or a mala to count keeps the mind anchored to the body instead of drifting, which is often the real work.', 'Mantra Academy, mala practice'),
('bhakti_devotion', 'Householder Devotion', 'Kritagya Das and Karaveera Nivasini Dasi teach from a specific lineage position — householder Yogis, not renunciates, living Bhakti Marga in the middle of ordinary family life. Devotion, in this tradition, was never meant to require leaving your life behind — only bringing more presence into it.', 'Bhakti Marga tradition, householder path'),
('bhakti_devotion', 'Jai Gurudev as Practice', 'The greeting "Jai Gurudev" is more than a phrase in this lineage — it is a small, repeated act of remembering the teacher who transmits the teaching, a way of staying oriented throughout an ordinary day. Try saying it once, quietly, before you open this app today.', 'Bhakti Marga greeting practice'),
('abundance', 'Wealth as Downstream', 'The Siddhas rarely treated wealth as a separate subject from health and inner balance — abundance was understood as something that flows naturally once Ojas, Agni, and the mind are in order, not something pursued independently of them. Chasing money while depleted rarely works for long; this tradition explains why.', 'Ayurveda-Abundance connection, Siddha Medicine framework'),
('protection', 'The Geometry of Coherence', 'Sacred geometry forms like the Sri Yantra are understood in this tradition as fields of coherence — patterns that organize scattered energy the way a magnet organizes iron filings, without force. You don''t need to understand the mathematics for the field to do its work.', 'Sacred geometry, protection teaching'),
('general', 'Advanced Herbology', 'Dravya Guna, advanced herbology, covers fifty classical herbs from the Charaka Samhita organized into ten Dashemani groups — a level of plant knowledge that took physicians a lifetime to master in the old tradition. What''s offered here is a genuine doorway into that depth, not a simplified version of it.', 'Dravya Guna — Agastyar Academy Module 20'),
('general', 'Why Two Systems, One Nexus', 'Ayurveda and Siddha Medicine share deep roots but diverged over centuries into two related, sometimes different, systems — which is why SQI teaches both rather than picking one. Where they agree, the teaching is more certain; where they differ, that difference itself is often instructive.', 'The Origin Story — Agastyar Academy Module 1');